<?php
namespace App\Domain\Accounting\Actions;
use App\Enums\JournalStatus;use App\Enums\ReconciliationStatus;use App\Models\BankReconciliation;use App\Models\BankReconciliationMatch;use App\Models\BankStatementLine;use App\Models\JournalEntryLine;use Illuminate\Support\Facades\Auth;use Illuminate\Support\Facades\DB;use Illuminate\Validation\ValidationException;
class ReconcileBankStatement{public function match(BankStatementLine $statement,JournalEntryLine $journal,int $amount,string $type='manual'):BankReconciliationMatch{return DB::transaction(function()use($statement,$journal,$amount,$type){$statement=BankStatementLine::query()->with('matches')->lockForUpdate()->findOrFail($statement->id);$reconciliation=$statement->bank_reconciliation_id?BankReconciliation::query()->with('bankAccount')->findOrFail($statement->bank_reconciliation_id):null;if(!$reconciliation||$journal->ledger_account_id!==$reconciliation->bankAccount->ledger_account_id||$journal->entry()->where('status',JournalStatus::Posted->value)->doesntExist())throw ValidationException::withMessages(['journal_entry_line_id'=>['The journal line is not a posted entry for this bank account.']]);$available=abs($statement->amount_minor)-(int)$statement->matches->sum('matched_amount_minor');$journalAmount=$statement->amount_minor>=0?$journal->debit_minor:$journal->credit_minor;$journalMatched=(int)BankReconciliationMatch::query()->where('journal_entry_line_id',$journal->id)->sum('matched_amount_minor');if($amount<=0||$amount>$available||$amount>$journalAmount-$journalMatched)throw ValidationException::withMessages(['matched_amount_minor'=>['The match exceeds the available statement or journal amount.']]);$match=BankReconciliationMatch::query()->create(['bank_statement_line_id'=>$statement->id,'journal_entry_line_id'=>$journal->id,'matched_amount_minor'=>$amount,'match_type'=>$type,'matched_by'=>Auth::id(),'matched_at'=>now()]);$statement->update(['status'=>$amount===$available?'matched':'partially_matched']);$reconciliation->update(['status'=>ReconciliationStatus::InProgress]);return $match;});}public function autoMatch(BankReconciliation $reconciliation):int{$count=0;$reconciliation->load('bankAccount');$reconciliation->statementLines()->where('status','unmatched')->each(function($statement)use($reconciliation,&$count){$line=JournalEntryLine::query()->where('ledger_account_id',$reconciliation->bankAccount->ledger_account_id)->whereHas('entry',fn($q)=>$q->where('status',JournalStatus::Posted->value)->whereDate('entry_date',$statement->transaction_date)->when($statement->reference,fn($query,$reference)=>$query->where('reference',$reference)))->where($statement->amount_minor>=0?'debit_minor':'credit_minor',abs($statement->amount_minor))->first();if($line){$this->match($statement,$line,abs($statement->amount_minor),'automatic');$count++;}});return $count;}public function complete(BankReconciliation $reconciliation):BankReconciliation{$reconciliation->load('statementLines.matches');$calculated=$reconciliation->opening_balance_minor+$reconciliation->statementLines->sum('amount_minor');if($calculated!==$reconciliation->closing_balance_minor)throw ValidationException::withMessages(['closing_balance_minor'=>['Opening balance plus statement activity does not equal the closing balance.']]);if($reconciliation->statementLines->contains(fn($line)=>$line->matches->sum('matched_amount_minor')!==abs($line->amount_minor)))throw ValidationException::withMessages(['statement_lines'=>['Every statement line must be fully matched.']]);$reconciliation->update(['status'=>ReconciliationStatus::Completed,'completed_by'=>Auth::id(),'completed_at'=>now()]);return $reconciliation->refresh();}}
